def count_cheap_pairs(N, T, A):
    """Counts the number of cheap pairs in the given array."""
    count = 0
    A.sort()  # Sort the array to apply two-pointer technique

    for i in range(N):
        for j in range(i + 1, N):
            if A[i] + A[j] <= T:
                count += 1
            else:
                break  # Since the array is sorted, we can break the inner loop

    return count

